                                <a href="#" className="p-4 bg-white/5 text-white/20 hover:text-white hover:bg-primary transition-all duration-500 rounded-full group-hover:rotate-45" aria-label={`View project ${project.title}`}>
                                    <ArrowUpRight size={24} />
                                </a>
                            </div>

                            <div className="mt-12 relative z-10 flex flex-col flex-1">
                                <p className="text-white/60 text-lg md:text-xl font-light leading-relaxed mb-8 max-w-sm">
                                    {project.desc}
                                </p>

                                {project.impact && (
                                    <div className="mb-12 border-l-2 border-primary/40 bg-primary/5 p-4 max-w-sm">
                                        <div className="text-[10px] font-mono text-primary font-bold uppercase tracking-widest mb-1">The Impact</div>
                                        <div className="text-white/90 text-sm font-medium leading-relaxed">{project.impact}</div>
                                    </div>
                                )}

                                <div className="flex flex-wrap gap-4 mt-auto">
                                    {project.tags.map((tag) => (
                                        <span key={tag} className="text-[10px] font-mono tracking-widest text-white/20">
                                            //{tag}
                                        </span>
                                    ))}
                                </div>
                            </div>

                            {/* Functional Gradient Overlay */}
                            <div className={cn("absolute inset-0 bg-gradient-to-br opacity-0 group-hover:opacity-100 transition-opacity duration-1000", project.color)} />
                        </motion.div>
                    ))}
                </div>
            </div>
        </Section>
    );
};

"use client";

import React, { useEffect, useState } from 'react';
import { Command } from 'cmdk';
import {
    Search,
    Terminal,
    Zap,
    Layout,
    Monitor,
    Github,
    Linkedin,
    Mail,
    ArrowRight,
    Command as CommandIcon
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const QuickCommand = () => {
    const [open, setOpen] = useState(false);

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                setOpen((open) => !open);
            }
        };

        document.addEventListener('keydown', down);
        return () => document.removeEventListener('keydown', down);
    }, []);

    return (
        <>
            <div className="fixed bottom-8 right-8 z-40 hidden lg:block">
                <button
                    onClick={() => setOpen(true)}
                    className="flex items-center gap-3 px-4 py-2 bg-black border border-white/5 text-white/40 hover:text-white hover:border-primary transition-all group grit-border"
                    aria-label="Open Command Menu"
                >
                    <CommandIcon size={14} />
                    <span className="font-mono text-[8px] uppercase tracking-widest">System_Access</span>
                    <span className="px-1.5 py-0.5 border border-white/10 rounded-sm text-[8px] opacity-40">ÔîÿK</span>
                </button>
            </div>

            <AnimatePresence>
                {open && (
                    <Command.Dialog
                        open={open}
                        onOpenChange={setOpen}
                        className="fixed inset-0 z-[100] flex items-center justify-center p-4"
                    >
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 bg-black/80 backdrop-blur-md"
                            onClick={() => setOpen(false)}
                        />

                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 10 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 10 }}
                            className="relative w-full max-w-[600px] bg-[#0A0A0A] border border-white/10 overflow-hidden grit-border"
                        >
                            <div className="flex items-center p-4 border-b border-white/5 bg-white/[0.02]">
                                <Search className="mr-3 text-white/20" size={18} />
                                <Command.Input
                                    placeholder="EX_SYSTEM_CMD: SEARCH..."
                                    className="flex-1 bg-transparent border-none outline-none text-white font-mono text-[16px] placeholder:text-white/10 lowercase"
                                />
                                <button
                                    onClick={() => setOpen(false)}
                                    className="p-1 hover:bg-white/5 transition-colors text-white/20"
                                >
                                    <span className="font-mono text-[8px] uppercase tracking-widest">ESC</span>
                                </button>
                            </div>

                            <Command.List className="max-h-[400px] overflow-y-auto p-2 scrollbar-hide">
                                <Command.Empty className="p-8 text-center">
                                    <span className="font-mono text-[8px] text-white/20 uppercase tracking-widest">Target_Not_Found // Error_404</span>
                                </Command.Empty>

                                <Command.Group heading="Navigation Nodes" className="p-2">
                                    <Item onSelect={() => { document.getElementById('contact')?.scrollIntoView(); setOpen(false); }}>
                                        <Mail size={16} /> 01 // Contact_Handshake
                                    </Item>
                                    <Item onSelect={() => { window.scrollTo({ top: 3000, behavior: 'smooth' }); setOpen(false); }}>
                                        <Zap size={16} /> 02 // Strategic_Deployments
                                    </Item>
                                </Command.Group>

                                <Command.Group heading="Technical Channels" className="p-2 border-t border-white/5 mt-2">
                                    <Item onSelect={() => window.open('https://github.com', '_blank')}>
                                        <Github size={16} /> SRC_CODE // GitHub_Access
                                    </Item>
                                    <Item onSelect={() => window.open('https://linkedin.com', '_blank')}>
                                        <Linkedin size={16} /> AUTH_VAL // LinkedIn_Verify
                                    </Item>
                                </Command.Group>

                                <div className="p-4 border-t border-white/5 bg-white/[0.01] flex justify-between items-center mt-2">
                                    <div className="flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                                        <span className="font-mono text-[8px] text-white/20 uppercase tracking-widest">System_VLD: Secure</span>
                                    </div>
                                    <span className="font-mono text-[8px] text-white/10 uppercase tracking-widest">ALX_ARC_01</span>
                                </div>
                            </Command.List>
                        </motion.div>
                    </Command.Dialog>
                )}
            </AnimatePresence>
        </>
    );
};

const Item = ({ children, onSelect }: { children: React.ReactNode; onSelect?: () => void }) => (
    <Command.Item
        onSelect={onSelect}
        className="flex items-center gap-4 p-4 text-white/40 hover:text-white hover:bg-white/[0.02] cursor-pointer transition-all border border-transparent hover:border-white/5 font-mono text-[16px] uppercase tracking-widest group"
    >
        {children}
        <ArrowRight size={12} className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity text-primary" />
    </Command.Item>
);
